    final Map<Sommet, Sommet> predecessors = new HashMap<>();
    Set<Sommet> unsettledNodes = new HashSet<>(graph.getSommets());
    Set<Sommet> settledNodes = new HashSet<>();

    for (Sommet sommet : graph.getSommets()) {
        distances.put(sommet, Double.POSITIVE_INFINITY);
