            if (settledNodes.contains(adjacent)) continue;
            double edgeWeight = arete.getPoids();
            if (distances.get(current) + edgeWeight < distances.get(adjacent)) {
                distances.put(adjacent, distances.get(current) + edgeWeight);
                predecessors.put(adjacent, current);
